VALUES
  ('social-worker-moex-03231', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年來新公共管理主義發展所累積的效應已經產生一連串影響管理者的趨勢，但不包括下列那一項？', '["強調社會服務提供者之間的競爭會帶來更有效果的服務", "強調消費主義（consumerism），管理者需注重服務使用者的意見回饋", "強調組織的績效管理（performance management）", "強調擴大公部門對社會服務的提供"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03232', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者的角色若是評估組織的目標、預期結果、需要的技術，以及界定組織與方案的輸入、轉化、輸出 與結果，這是承擔下列何種的管理責任？', '["整體系統的分析", "使命與目標的建立", "理想結構的建立", "理想工作設計的建立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03233', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '從人群關係學派理論萃取出來可以應用於人群服務組織管理的有效原則，不包括下列那一項？', '["體認組織文化與其次文化的重要性", "體認正式結構與層級體系的重要性", "了解團體對個人表現的影響", "了解及應用有意義的獎勵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03234', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某類型的人群服務機構，其組織是依據特定領域的專門知識決定結構，例如營業部門負責臨床服務，人 力資源部門負責員工發展，這是採取何種部門化（departmentalization）的設計？', '["按方案部門化（departmentalization by program）", "按市場部門化（departmentalization by market）", "按功能部門化（departmentalization by function）", "按消費者/案主部門化（departmentalization by consumer/client）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03235', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在員工的考核評估中，評核者很容易因自己的某些缺點，而在考核時對受評者類似的缺點故意忽視，而 造成考核上的偏失，這是屬於何種員工考核評估的偏誤類型？', '["盲點效應（blindness effect）", "月暈效應（halo effect）", "尖角效應（horn effect）", "初始效應（primacy effect）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03236', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '進行方案評估時，評估者欲了解方案達到其整體方案目標的程度，例如接受高風險家庭服務處遇的家庭， 其處遇的有效程度，這是屬於何種評估類型？', '["需求評估（evaluation of needs）", "過程評估（evaluation of process）", "成果評估（evaluation of outcome）", "影響性評估（evaluation of impact）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03237', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年來社會工作發展趨勢與全面品質管理（total quality management）的連結受到重視，下列何者對於連 結要件的敘述是錯誤的？', '["著重使用者導向的績效測量和指標發展", "著重財務主導組織", "著重於服務輸送時的勞務", "強調在組織內減少無附加價值的措施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03238', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Gundersdorf（1977）針對社會服務機構提出四種預算類型，其中一種是用來檢視「機構提供服務及產出 之成本支出，旨在測量生產力，計算出服務之單位成本」，這是屬於下列何種預算之類型？', '["非預算系統（non-budgeting system）", "單項預算（line-item budgeting）", "功能預算（functional budgeting）", "方案預算（program budgeting）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03239', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在各種績效評估方法中，特別重視流程，而非投入或產出的方法是：', '["特質評估法", "職能評估法", "行為評估法", "產出評估法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03240', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一位新進社工剛到社會福利機構報到，人力資源部門的同仁會介紹各種有關組織的資訊，這個過程稱為：', '["引導", "督導", "教練", "職內訓練"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
